CREATE TABLE IF NOT EXISTS `BIZ_EMERGENCY_FACILITY` (
  `id` varchar(64) NOT NULL COMMENT '主键',
  `tenant_id` varchar(64) DEFAULT NULL COMMENT '租户id',
  `name` varchar(128) NOT NULL COMMENT '设施名称',
  `type` varchar(64) NOT NULL COMMENT '设施类型',
  `lng` decimal(10,6) NOT NULL COMMENT '经度',
  `lat` decimal(10,6) NOT NULL COMMENT '纬度',
  `sort_code` int DEFAULT NULL COMMENT '排序码',
  `delete_flag` varchar(32) DEFAULT NULL COMMENT '删除标志',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `create_user` varchar(64) DEFAULT NULL COMMENT '创建人',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  `update_user` varchar(64) DEFAULT NULL COMMENT '更新人',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='应急设施';

ON DUPLICATE KEY UPDATE
  `tenant_id` = VALUES(`tenant_id`),
  `name` = VALUES(`name`),
  `type` = VALUES(`type`),
  `lng` = VALUES(`lng`),
  `lat` = VALUES(`lat`),
  `sort_code` = VALUES(`sort_code`),
  `delete_flag` = VALUES(`delete_flag`),
  `create_time` = VALUES(`create_time`),
  `create_user` = VALUES(`create_user`),
  `update_time` = VALUES(`update_time`),
  `update_user` = VALUES(`update_user`);
